function solve(s) {
    const seen = new Set();
    const segments = [];
    let start = 0;
    while (start < s.length) {
        let current = '';
        let i = start;
        while (true) {
            if (i >= s.length) {
                break;
            }
            current += s[i];
            if (!seen.has(current)) {
                break;
            } else {
                i++;
            }
        }
        seen.add(current);
        segments.push(current);
        start = i + 1;
    }
    return segments;
}
